// ==UserScript==
// @name         Claude.ai 出力完了ビープ
// @namespace    http://tampermonkey.net/
// @version      16.0
// @description  Claude.aiの出力が完了したら通知音で知らせる（自動継続対応）
// @match        https://claude.ai/*
// @grant        none
// @run-at       document-idle
// ==/UserScript==

(function () {
  'use strict';

  // ══════════════════════════════════════════
  //  設定
  // ══════════════════════════════════════════

  // 通知モード: 'beep' = オシレータービープ / 'wav' = WAVファイル
  var NOTIFY_MODE = 'wav';

  // ── beep モード設定 ──
  var BEEP_FREQUENCY = 880;
  var BEEP_DURATION  = 150;
  var BEEP_VOLUME    = 0.3;
  var BEEP_COUNT     = 2;
  var BEEP_INTERVAL  = 250;
  var BEEP_WAVE_TYPE = 'sine';

  // ── wav モード設定 ──
  var WAV_VOLUME = 0.5;

  // ── 自動継続対応 ──
  var CONTINUE_WAIT = 5000;

  // ══════════════════════════════════════════

  var WAV_BASE64 = '';

  // AudioContext
  var audioCtx = null;
  var decodedWavBuffer = null;

  function ensureAudioCtx() {
    if (!audioCtx) {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      if (NOTIFY_MODE === 'wav') {
        var bin = atob(WAV_BASE64);
        var buf = new ArrayBuffer(bin.length);
        var view = new Uint8Array(buf);
        for (var i = 0; i < bin.length; i++) view[i] = bin.charCodeAt(i);
        audioCtx.decodeAudioData(buf).then(function(decoded) {
          decodedWavBuffer = decoded;
          console.log('[Claude Beep] WAVデコード完了');
        }).catch(function(e) { console.warn('[Claude Beep] WAVデコード失敗:', e); });
      }
    }
    if (audioCtx.state === 'suspended') {
      audioCtx.resume();
    }
  }
  document.addEventListener('click', ensureAudioCtx, true);
  document.addEventListener('keydown', ensureAudioCtx, true);

  function playWav() {
    if (!audioCtx || audioCtx.state !== 'running' || !decodedWavBuffer) return;
    var source = audioCtx.createBufferSource();
    var gain = audioCtx.createGain();
    source.buffer = decodedWavBuffer;
    gain.gain.value = WAV_VOLUME;
    source.connect(gain);
    gain.connect(audioCtx.destination);
    source.start(0);
  }

  function playBeep() {
    if (!audioCtx || audioCtx.state !== 'running') return;
    var osc = audioCtx.createOscillator();
    var gain = audioCtx.createGain();
    osc.type = BEEP_WAVE_TYPE;
    osc.frequency.value = BEEP_FREQUENCY;
    gain.gain.value = BEEP_VOLUME;
    osc.connect(gain);
    gain.connect(audioCtx.destination);
    var now = audioCtx.currentTime;
    osc.start(now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + BEEP_DURATION / 1000);
    osc.stop(now + BEEP_DURATION / 1000 + 0.05);
  }

  var lastNotifyTime = 0;
  function playNotification() {
    var now = Date.now();
    if (now - lastNotifyTime < 2000) return;
    lastNotifyTime = now;
    if (NOTIFY_MODE === 'wav') {
      playWav();
    } else {
      for (var i = 0; i < BEEP_COUNT; i++) {
        setTimeout(playBeep, i * BEEP_INTERVAL);
      }
    }
    console.log('[Claude Beep] 出力完了 🔔 (' + NOTIFY_MODE + ')');
  }

  // ── 停止ボタン & 続けるボタン監視 ──
  var stopButtonVisible = false;
  var pendingTimer = null;
  var STOP_SELECTOR = 'button[aria-label="\u5FDC\u7B54\u3092\u505C\u6B62"], button[aria-label="Stop Response"], button[aria-label="Stop response"]';

  function isStopButtonPresent() {
    return !!document.querySelector(STOP_SELECTOR);
  }

  function isContinueButtonPresent() {
    // AutoContinueと同じセレクタ: message-warning内のボタン or バナー内のボタン
    var warning = document.querySelector('[data-testid="message-warning"]');
    if (warning && warning.querySelector('button')) return true;
    // data-color-context="main" 内の再試行ボタン
    var banners = document.querySelectorAll('div[data-color-context="main"]');
    for (var i = 0; i < banners.length; i++) {
      if (banners[i].querySelector('svg') && banners[i].querySelector('button')) return true;
    }
    return false;
  }

  function isStillGenerating() {
    return isStopButtonPresent() || isContinueButtonPresent();
  }

  function checkStopButton() {
    var visible = isStopButtonPresent();

    if (!stopButtonVisible && visible) {
      stopButtonVisible = true;
      if (pendingTimer) {
        clearTimeout(pendingTimer);
        pendingTimer = null;
        console.log('[Claude Beep] 生成再開を検知 → 通知キャンセル');
      }
      console.log('[Claude Beep] 生成開始');

    } else if (stopButtonVisible && !visible) {
      stopButtonVisible = false;
      console.log('[Claude Beep] 停止ボタン消滅 → ' + (CONTINUE_WAIT / 1000) + '秒待機...');

      if (pendingTimer) clearTimeout(pendingTimer);
      pendingTimer = setTimeout(function() {
        pendingTimer = null;
        if (!isStillGenerating()) {
          playNotification();
        } else {
          console.log('[Claude Beep] まだ継続中 → 通知スキップ、再監視');
          // 継続中なので再び停止ボタンの出現を待つ
          stopButtonVisible = isStopButtonPresent();
        }
      }, CONTINUE_WAIT);
    }
  }

  // MutationObserver + setInterval 併用
  var observer = new MutationObserver(function() {
    checkStopButton();
  });
  observer.observe(document.body, {
    childList: true,
    subtree: true
  });
  setInterval(checkStopButton, 500);

  console.log('[Claude Beep] v16.0 起動 ✓ モード: ' + NOTIFY_MODE + ' (自動継続対応)');
})();